To fix the XSS vulnerability in the provided Java code snippet, you need to properly encode the user input before embedding it in the HTML response. Here is an updated version of the code that uses OWASP's ESAPI library for encoding:

```java
import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        out.println("<html><head><title>XSS Fixed Page</title></head><body>");
        out.println("<h1>User Input:</h1>");

        // Encode user input to prevent XSS
        HTMLEntityCodec codec = ESAPI.encoder().getHTMLEntityCodec();
        String encodedUserInput = codec.encodeForHTML(userInput);

        out.println("<p>" + encodedUserInput + "</p>");

        out.println("</body></html>");
    }
}
``

